6	// Simple in-memory rate limiter: max 5 submissions per IP per hour
7	const rateLimitMap = new Map<string, { count: number; resetAt: number }>();
8	
9	function checkRateLimit(ip: string): boolean {
10	  const now = Date.now();
11	  const entry = rateLimitMap.get(ip);
12	
13	  if (!entry || now > entry.resetAt) {
14	    rateLimitMap.set(ip, { count: 1, resetAt: now + 3600_000 });
15	    return true;
16	  }
17	
18	  if (entry.count >= 5) return false;
19	  entry.count++;
20	  return true;
21	}
22	
23	// Clean up stale entries every 10 minutes
24	setInterval(() => {
25	  const now = Date.now();
26	  for (const [key, val] of rateLimitMap) {
27	    if (now > val.resetAt) rateLimitMap.delete(key);
28	  }
29	}, 600_000);
