41	interface SubmitBody {
42	  items: SubmitItem[];
43	  customerName: string;
44	  customerEmail: string;
45	  customerPhone?: string;
46	  paymentMethod: "cash" | "credit";
47	  deliveryMethod: "mail" | "instore";
48	  bankSortCode?: string;
49	  bankAccountNumber?: string;
50	  isOver18: boolean;
51	  conditionDeclaration: boolean;
52	  notes?: string;
53	}
