55	export async function POST(request: Request) {
56	  try {
57	    // Rate limit by IP
58	    const forwarded = request.headers.get("x-forwarded-for");
59	    const ip = forwarded?.split(",")[0]?.trim() || "unknown";
60	    if (!checkRateLimit(ip)) {
61	      return NextResponse.json(
62	        { error: "Too many submissions. Please try again later." },
63	        { status: 429 }
64	      );
65	    }
66	
67	    const body: SubmitBody = await request.json();
68	
69	    // Validate required fields
70	    if (!body.items || !Array.isArray(body.items) || body.items.length === 0) {
71	      return NextResponse.json({ error: "No items provided." }, { status: 400 });
72	    }
73	    if (!body.customerName?.trim()) {
74	      return NextResponse.json({ error: "Name is required." }, { status: 400 });
75	    }
76	    if (!body.customerEmail?.trim() || !body.customerEmail.includes("@")) {
77	      return NextResponse.json({ error: "Valid email is required." }, { status: 400 });
78	    }
79	    if (!["cash", "credit"].includes(body.paymentMethod)) {
80	      return NextResponse.json({ error: "Invalid payment method." }, { status: 400 });
81	    }
82	    if (!["mail", "instore"].includes(body.deliveryMethod)) {
83	      return NextResponse.json({ error: "Invalid delivery method." }, { status: 400 });
84	    }
85	    if (!body.isOver18) {
86	      return NextResponse.json({ error: "You must be 18 or over." }, { status: 400 });
87	    }
88	    if (!body.conditionDeclaration) {
89	      return NextResponse.json({ error: "Condition declaration is required." }, { status: 400 });
90	    }
91	
92	    // Validate individual items
93	    for (const item of body.items) {
94	      if (!item.sku || !item.quantity || item.quantity <= 0) {
95	        return NextResponse.json({ error: "Invalid item in submission." }, { status: 400 });
96	      }
97	    }
98	
99	    // Re-validate prices against current buylist (allow 10% drift)
100	    const [creditRes, cashRes] = await Promise.all([
101	      fetchPrices({ game: "one-piece", channel: "tradein-credit", limit: 500 }),
102	      fetchPrices({ game: "one-piece", channel: "tradein-cash", limit: 500 }),
103	    ]);
104	
105	    const currentCreditMap = new Map<string, number>();
106	    for (const item of creditRes.items) {
107	      currentCreditMap.set(item.sku, item.channel_price ?? 0);
108	    }
109	    const currentCashMap = new Map<string, number>();
110	    for (const item of cashRes.items) {
111	      currentCashMap.set(item.sku, item.channel_price ?? 0);
112	    }
113	
114	    for (const item of body.items) {
115	      const currentCredit = currentCreditMap.get(item.sku) ?? 0;
116	      const currentCash = currentCashMap.get(item.sku) ?? 0;
117	
118	      if (item.credit_price > 0 && currentCredit > 0) {
119	        const drift = Math.abs(item.credit_price - currentCredit) / currentCredit;
120	        if (drift > 0.10) {
121	          return NextResponse.json(
122	            { error: `Price has changed for ${item.name}. Please refresh the buylist.` },
123	            { status: 409 }
124	          );
125	        }
126	      }
127	      if (item.cash_price > 0 && currentCash > 0) {
128	        const drift = Math.abs(item.cash_price - currentCash) / currentCash;
129	        if (drift > 0.10) {
130	          return NextResponse.json(
131	            { error: `Price has changed for ${item.name}. Please refresh the buylist.` },
132	            { status: 409 }
133	          );
134	        }
135	      }
136	    }
137	
138	    // Calculate totals
139	    let cashTotal = 0;
140	    let creditTotal = 0;
141	    for (const item of body.items) {
142	      cashTotal += item.cash_price * item.quantity;
143	      creditTotal += item.credit_price * item.quantity;
144	    }
145	
146	    // Generate reference and expiry
147	    const reference = await generateReference();
148	    const expiresAt = new Date();
149	    expiresAt.setDate(expiresAt.getDate() + 7);
150	
151	    // Insert into DB
152	    await createSubmission({
153	      reference,
154	      customerName: body.customerName.trim(),
155	      customerEmail: body.customerEmail.trim().toLowerCase(),
156	      customerPhone: body.customerPhone?.trim(),
157	      paymentMethod: body.paymentMethod,
158	      bankSortCode: body.bankSortCode,
159	      bankAccountNumber: body.bankAccountNumber,
160	      deliveryMethod: body.deliveryMethod,
161	      isOver18: body.isOver18,
162	      notes: body.notes,
163	      cashTotal,
164	      creditTotal,
165	      expiresAt,
166	      items: body.items,
167	    });
168	
169	    // Send confirmation email (non-blocking — don't fail submission if email fails)
170	    try {
171	      await sendConfirmationEmail({
172	        reference,
173	        customerName: body.customerName.trim(),
174	        customerEmail: body.customerEmail.trim().toLowerCase(),
175	        paymentMethod: body.paymentMethod,
176	        deliveryMethod: body.deliveryMethod,
177	        items: body.items.map((i) => ({
178	          name: i.name,
179	          card_number: i.card_number,
180	          quantity: i.quantity,
181	          cash_price: i.cash_price,
182	          credit_price: i.credit_price,
183	        })),
184	        cashTotal,
185	        creditTotal,
186	        expiresAt,
187	      });
188	    } catch (emailErr) {
189	      console.error("[tradein] Email failed but submission succeeded:", emailErr);
190	    }
191	
192	    return NextResponse.json({
193	      reference,
194	      expiresAt: expiresAt.toISOString(),
195	      cashTotal,
196	      creditTotal,
197	    });
198	  } catch (err) {
199	    console.error("[tradein] Submit error:", err);
200	    return NextResponse.json(
201	      { error: "Internal server error. Please try again." },
202	      { status: 500 }
203	    );
204	  }
205	}
