6	function makeToken(password: string): string {
7	  return crypto.createHmac("sha256", "kingdom-admin").update(password).digest("hex");
8	}
9	
10	export async function POST(request: Request) {
11	  try {
12	    const { password } = await request.json();
13	
14	    if (!ADMIN_PASSWORD) {
15	      return NextResponse.json({ error: "Admin not configured." }, { status: 503 });
16	    }
17	
18	    if (password !== ADMIN_PASSWORD) {
19	      return NextResponse.json({ error: "Wrong password." }, { status: 401 });
20	    }
21	
22	    const token = makeToken(ADMIN_PASSWORD);
23	    const res = NextResponse.json({ ok: true });
24	    res.cookies.set("admin_token", token, {
25	      httpOnly: true,
26	      secure: true,
27	      sameSite: "strict",
28	      path: "/",
29	      maxAge: 60 * 60 * 24, // 24 hours
30	    });
31	
32	    return res;
33	  } catch {
34	    return NextResponse.json({ error: "Bad request." }, { status: 400 });
